import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';

import { AuthGuard } from 'app/authorization/auth-guard.service';
import { AdminComponent } from './admin.component';
import { StartComponent } from './bank-features/start/start.component';
import { FourZeroFourComponent } from './four-zero-four/four-zero-four.component';



const routes: Routes = [
  {
    path: '',
    component: AdminComponent,
    canActivate: [AuthGuard],
    children: [{
      path: 'cfe',
      loadChildren: () => import('./bank-features/cfe/cfe.module').then(m => m.CFEModule)
    },
    {
      path: 'cp',
      loadChildren: () => import('./bank-features/cp/cp.module').then(m => m.CPModule)
    }, {
      path: 'ge',
      loadChildren: () => import('./bank-features/ge/ge.module').then(m => m.GEModule)
    }, {
      path: 'wacai',
      loadChildren: () => import('./wacai/wacai.module').then(m => m.WacaiModule)
    }, {
      path: '',
      component: StartComponent
    }, {
      path: '**',
      component: FourZeroFourComponent
    }]
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})

export class AdminRoutingModule {

}