import { AfterViewInit, Component, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { MatSidenav } from '@angular/material/sidenav';
import { ActivatedRoute, Router } from '@angular/router';
import { BehaviorSubject, fromEvent, Subscription } from 'rxjs';

import { MENU_ITEMS } from 'src/data/menu-items';
import { WACAI_MENU } from 'src/data/wacai-menu';

import { CommunicationService } from 'app/shared/services/communication.service';
import { NotificationService } from 'app/shared/services/notification.service';



@Component({
  selector: 'app-admin',
  templateUrl: './admin.component.html',
  styleUrls: ['./admin.component.scss']
})
export class AdminComponent implements OnInit, AfterViewInit, OnDestroy {
  menuItems = MENU_ITEMS.concat(WACAI_MENU);

  @ViewChild('leftSide') private leftSidenav: MatSidenav;
  @ViewChild('rightSide') private rightSidenav: MatSidenav;
  private secondaryOutletState = new BehaviorSubject<boolean>(false);
  private subscription = new Subscription();

  constructor(
    private router: Router,
    private route: ActivatedRoute,
    private communication: CommunicationService,
    private notification: NotificationService
  ) { }

  ngOnInit(): void {
    // this.notification.showInitLoading();
    this.subscription.add(
      fromEvent(window, 'unload').subscribe(() => {
        localStorage.setItem('redirectUrl', this.router.routerState.snapshot.url);
      })
    );
  }

  ngAfterViewInit(): void {
    setTimeout(() => {
      this.subscription.add(
        this.secondaryOutletState.subscribe((state) => {
          if (state) {
            this.rightSidenav.open();
          } else {
            this.rightSidenav.close();
          }
        })
      );
      this.subscription.add(
        this.communication.acceptFullScreenCommand().subscribe((state) => {
          if (state) {
            this.leftSidenav.close();
          } else {
            this.leftSidenav.open();
          }
        })
      );
    });
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  onSecondaryOutletActivate(event): any {
    this.secondaryOutletState.next(true);
  }

  onSecondaryOutletDeactivate(event): any {
    this.secondaryOutletState.next(false);
  }
}
