import { AfterViewInit, Component, ElementRef, HostListener, Input, OnDestroy, OnInit, Renderer2 } from '@angular/core';
import { Overlay, OverlayRef } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';
import { Subject, Subscription } from 'rxjs';
import { debounceTime } from 'rxjs/operators';

import { INavigationMenuItem } from './i-navigation-menu';
import { EventService } from 'app/shared/services/event.service';



@Component({
  selector: 'app-navigation-menu',
  templateUrl: './navigation-menu.component.html',
  styleUrls: ['./navigation-menu.component.scss']
})
export class NavigationMenuComponent implements OnInit, AfterViewInit, OnDestroy {
  @Input() items: INavigationMenuItem[];
  mouseEntered = false;

  private overlayRef: OverlayRef;
  private parentMenu: NavigationMenuComponent;
  private childMenu: NavigationMenuComponent;
  private scrollbar: HTMLElement;;
  private liElement: HTMLElement;
  private openCommand$ = new Subject<INavigationMenuItem>();
  private closeCommand$ = new Subject<INavigationMenuItem>();
  private subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private renderer: Renderer2,
    private overlay: Overlay,
    private eventService: EventService
  ) {
  }

  ngOnInit(): void {
    const positionStrategy = this.overlay.position().flexibleConnectedTo(this.elementRef);

    positionStrategy.withPositions([{
      offsetX: -1,
      offsetY: 0,
      originX: 'end',
      originY: 'top',
      overlayX: 'start',
      overlayY: 'top'
    }]);
    this.overlayRef = this.overlay.create({
      backdropClass: 'cdk-overlay-invisible-backdrop',
      disposeOnNavigation: true,
      hasBackdrop: false,
      positionStrategy,
      scrollStrategy: this.overlay.scrollStrategies.noop(),
      width: 330
    });
    this.scrollbar = this.renderer.createElement('div');
    this.renderer.addClass(this.scrollbar, 'scrollbar');
  }

  ngAfterViewInit(): void {
    setTimeout(() => {
      this.detectScrollbar();
    }, 100);

    this.subscription.add(
      this.eventService.onViewportDimensionChange().subscribe((change) => {
        if (change.height) {
          this.detectScrollbar();
        }
      })
    );
    this.subscription.add(
      this.openCommand$.pipe(debounceTime(11)).subscribe((menuData) => {
        this.openMenu(menuData);
      })
    );
    this.subscription.add(
      this.closeCommand$.pipe(debounceTime(10)).subscribe(() => {
        if (this.isAbleToCloseMenu()) {
          this.closeMenu();
          this.clearMenu(this.parentMenu);
        }
      })
    );
  }

  ngOnDestroy(): void {
    this.closeCommand$.complete();
    this.subscription.unsubscribe();
  }

  @HostListener('mouseenter')
  onMouseEnter(): void {
    this.mouseEntered = true;
  }

  @HostListener('mouseleave')
  onMouseLeave(): void {
    this.mouseEntered = false;
    this.closeCommand$.next(null);
  }

  onMouseEnterItem(event: MouseEvent, menuData: INavigationMenuItem): void {
    this.toggleActiveClass(false);
    this.liElement = this.getParentLi(event.target as HTMLElement);
    this.openCommand$.next(menuData);
  }

  onMouseLeaveItem(event: MouseEvent, menuData: INavigationMenuItem): void {
    this.liElement = this.getParentLi(event.target as HTMLElement);
    this.closeCommand$.next(menuData);
  }

  onScroll(container: HTMLElement): void {
    this.renderer.setStyle(this.scrollbar, 'top', container.scrollTop + 'px');
  }

  getRouterLink(menuData: INavigationMenuItem): string {
    if (menuData.url) {
      return './admin/' + menuData.url;
    }

    return '';
  }

  openMenu(menuData: INavigationMenuItem): void {
    const children = menuData.children;

    this.closeMenu();
    if (children && children.length) {
      this.overlayRef.updateSize({
        height: (this.elementRef.nativeElement as HTMLElement).offsetHeight
      });
      const portal = new ComponentPortal(NavigationMenuComponent);
      const compRef = this.overlayRef.attach(portal);
  
      compRef.instance.items = children;
      compRef.instance.parentMenu = this;
      this.childMenu = compRef.instance;
      this.toggleActiveClass(true);
    }
  }

  closeMenu(): void {
    this.overlayRef.detach();
    this.childMenu = undefined;
    this.toggleActiveClass(false);
  }

  clearMenu(menu: NavigationMenuComponent): void {
    if (menu && menu.isAbleToCloseMenu()) {
      menu.overlayRef.detach();
      menu.childMenu = undefined;
      menu.toggleActiveClass(false);
      if (menu.parentMenu) {
        menu.clearMenu(menu.parentMenu);
      }
    }
  }

  isAbleToCloseMenu(): boolean {
    if (this.childMenu) {
      return !this.childMenu.mouseEntered && this.childMenu.isAbleToCloseMenu();
    }
    return true;
  }

  private detectScrollbar(): void {
    const element = this.elementRef.nativeElement.children[0] as HTMLElement;
    const scrollHeight = element.scrollHeight;
    const offsetHeight = element.offsetHeight;

    if (scrollHeight > offsetHeight) {
      this.renderer.addClass(element, 'with-scrollbar');
      this.renderer.appendChild(this.elementRef.nativeElement, this.scrollbar);
      this.renderer.setStyle(this.scrollbar, 'height', offsetHeight * (offsetHeight / scrollHeight) + 'px');
    } else {
      this.renderer.removeClass(element, 'with-scrollbar');
      this.renderer.removeChild(this.elementRef.nativeElement, this.scrollbar);
    }
  }

  private getParentLi(el: HTMLElement): HTMLElement {
    if (el) {
      var tagName = (el.tagName || '').toLowerCase();

      if (tagName === 'li') {
        return el;
      } else if (tagName === 'ul' || tagName === 'body') {
        return null;
      } else {
        return this.getParentLi(el.parentElement);
      }
    }
  }

  private toggleActiveClass(isToAdd: boolean): void {
    if (this.liElement) {
      if (isToAdd) {
        this.renderer.addClass(this.liElement, 'open');
      } else {
        this.renderer.removeClass(this.liElement, 'open');
      }
    }
  }
}
